import { Link } from "react-router-dom";

function Home() {
  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold">Movie Search App 🎬</h1>

      <Link
        to="/movie/tt3896198"
        className="text-blue-500 underline mt-4 block"
      >
        Go to Sample Movie
      </Link>
    </div>
  );
}

export default Home;
